import{_ as a,o as i,c as t,ae as o}from"./chunks/framework.B6gjLfeO.js";const c=JSON.parse('{"title":"CleverTap Configuration","description":"","frontmatter":{"title":"CleverTap Configuration","slug":"clevertap-configuration"},"headers":[],"relativePath":"developer-hub/clevertap-configuration.md","filePath":"developer-hub/clevertap-configuration.md"}'),r={name:"developer-hub/clevertap-configuration.md"};function n(l,e,s,p,d,u){return i(),t("div",null,[...e[0]||(e[0]=[o(`<p><em>[Image: 1328]</em></p><h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h2><p>Clevertap personalization links work with the following ESPs:</p><ol><li>Amazon SES</li><li>Mailgun</li><li>Mandrill</li><li>Sendgrid</li></ol><p>Use the corresponding guides below to set up CleverTap with your ESP.</p><h2 id="how-does-it-work" tabindex="-1">How does it work? <a class="header-anchor" href="#how-does-it-work" aria-label="Permalink to &quot;How does it work?&quot;">​</a></h2><ol><li><p>User clicks on a link in an email from their mobile mail client (Gmail, Apple Mail, etc.)</p></li><li><p>If the user has the app installed and the link has a corresponding screen in the app, the app will open and deep link the user to the right content.</p><ul><li>Ex. Product detail page, category shopping page, etc.</li></ul></li><li><p>If the user does not have the app installed or the link only corresponds to a screen on the web, the user is routed to the website using their default mobile web browser.</p><ul><li>Ex. Unsubscribe link, privacy policy, etc.</li></ul></li><li><p>Obtained or set up your CleverTap <strong>click tracking domain</strong> (CTD). Reach out to your CleverTap account manager for assistance on this.</p></li></ol><h2 id="prerequisites" tabindex="-1">Prerequisites <a class="header-anchor" href="#prerequisites" aria-label="Permalink to &quot;Prerequisites&quot;">​</a></h2><div class="info custom-block"><p class="custom-block-title">Required Roles</p><p>Branch&#39;s Branch Email requires the following roles involved in order to enable:</p><ul><li>Developers</li><li>CRM/Email Team</li><li>CleverTap Account Manager / Support Team</li></ul></div><p>In order to enable CleverTap, you must first:</p><ol><li><p>Have admin access to your <a href="https://dashboard.branch.io/" target="_blank" rel="noreferrer">Branch Dashboard</a>.</p></li><li><p>Have Branch&#39;s Engagement <a href="./packaging.html">product</a> enabled for your Branch Account.</p></li><li><p>Implement the Branch SDK into your mobile app (<a href="./ios-sdk-overview.html">iOS</a> | <a href="./android-sdk-overview.html">Android</a>)</p><ul><li><p>Set Up Deep Link Routing. How your mobile app routes to in-app content will determine how you will create and tag your Branch Links.</p><ul><li><a href="./in-app-routing.html#option-1-build-custom-routing-inside-the-routing-callback">Build custom routing inside the routing callback</a></li><li><a href="./in-app-routing.html#option-2-let-branch-use-your-existing-deep-link-routing">Let Branch use your existing deep link routing</a></li></ul></li><li><p><a href="./track-branch-events.html">Track events</a></p></li></ul></li><li><p>Review our <a href="./email-overview.html">Email Overview</a> and <a href="./email-integration-guide.html">Basic Email Integration Guide</a> to understand the feature and our integrations.</p></li></ol><h2 id="enable-and-configure-clevertap" tabindex="-1">Enable and Configure CleverTap <a class="header-anchor" href="#enable-and-configure-clevertap" aria-label="Permalink to &quot;Enable and Configure CleverTap&quot;">​</a></h2><h3 id="enable-clevertap" tabindex="-1">Enable CleverTap <a class="header-anchor" href="#enable-clevertap" aria-label="Permalink to &quot;Enable CleverTap&quot;">​</a></h3><div class="danger custom-block"><p class="custom-block-title">COMPLETE THE Branch Email INTEGRATION GUIDE</p><p>Before you can start sending Branch Links in your emails with Clevertap, you must complete the standard <a href="./universal-email-integration-guide.html">Branch Email Integration Guide</a>.</p></div><h3 id="configure-clevertap" tabindex="-1">Configure CleverTap <a class="header-anchor" href="#configure-clevertap" aria-label="Permalink to &quot;Configure CleverTap&quot;">​</a></h3><h2 id="_1-set-up-link-behavior" tabindex="-1">1. Set up Link Behavior <a class="header-anchor" href="#_1-set-up-link-behavior" aria-label="Permalink to &quot;1. Set up Link Behavior&quot;">​</a></h2><p>Once you have completed the ESP configuration, you can start adding CleverTap links to the email body.</p><p>With your ESP make sure to add the URL parameter <code>$follow_redirect=true</code> to every CleverTap link in the email body. This will indicate to Branch that this link is a CleverTap link. As soon as Branch detects this parameter Branch backend will follow the Clevertap link, receive personalization data from their servers, and send it to the mobile App/Web.</p><h2 id="_2-disable-html-sanitization" tabindex="-1">2. Disable HTML Sanitization <a class="header-anchor" href="#_2-disable-html-sanitization" aria-label="Permalink to &quot;2. Disable HTML Sanitization&quot;">​</a></h2><p>CleverTap uses an HTML editor for creating email bodies. It has been observed that CleverTap editors<br> scrape our deep link parameter such as <code>universal=”true”</code> or <code>deeplink=”true”</code> from the URL which causes the deep links to fail.</p><p>By disabling Clevertap&#39;s HTML sanitization, the above parameters are not scraped/removed from the link.</p><p>Before you go live with your campaign, please reach out to your CleverTap account manager and ask them to disable the HTML Sanitization. This will usually take 3 -4 working days to turn off. Please plan accordingly.</p><h2 id="_3-send-deep-links-via-email-editor" tabindex="-1">3. Send Deep Links via Email Editor <a class="header-anchor" href="#_3-send-deep-links-via-email-editor" aria-label="Permalink to &quot;3. Send Deep Links via Email Editor&quot;">​</a></h2><p>You can use the HTML and Custom HTML (Dynamic Content) elements available in the drag and drop editor to form and embed deep links in your email.</p><h2 id="add-branch-links-to-your-emails" tabindex="-1">Add Branch Links to your Emails <a class="header-anchor" href="#add-branch-links-to-your-emails" aria-label="Permalink to &quot;Add Branch Links to your Emails&quot;">​</a></h2><p>CleverTap personalization links work with the following ESPs:</p><h2 id="amazon-ses" tabindex="-1">Amazon SES <a class="header-anchor" href="#amazon-ses" aria-label="Permalink to &quot;Amazon SES&quot;">​</a></h2><p><strong>1. Create Flagged Links</strong></p><p>Before you start setting up your email campaigns, you need to determine what flow you want the user to experience and flag your email link accordingly.</p><p>Use the following markup for the links to work properly:</p><ul><li><strong>Deep linking users to in-app content</strong>: add <code>$deep_link=true</code> to your links as a query parameter</li><li><strong>Linking users to web-only content</strong>: add <code>$web_only=true</code> to your links as a query parameter</li></ul><p><strong>2. Configure Clevertap</strong></p><p>Please follow all of the <a href="./clevertap-data.html#configure-clevertap">Configure Clevertap</a> steps to ensure everything is working properly before you go live.</p><h2 id="mailgun" tabindex="-1">Mailgun <a class="header-anchor" href="#mailgun" aria-label="Permalink to &quot;Mailgun&quot;">​</a></h2><p><strong>1. Create Flagged Links</strong></p><p>Before you start setting up your email campaigns, you need to determine what flow you want the user to experience and flag your email link accordingly.</p><p>Use the following markup for the links to work properly:</p><ul><li><strong>Deep linking users to in-app content</strong>: add <code>deeplink=&quot;true&quot;</code> to the HTML</li><li><strong>Linking users to web-only content</strong>: No need to add anything</li></ul><p><strong>2. Configure Clevertap</strong></p><p>Please follow all of the <a href="./clevertap-data.html#configure-clevertap">Configure Clevertap</a> steps to ensure everything is working properly before you go live.</p><h2 id="mandrill" tabindex="-1">Mandrill <a class="header-anchor" href="#mandrill" aria-label="Permalink to &quot;Mandrill&quot;">​</a></h2><p><strong>1. Create Flagged Links</strong></p><p>Before you start setting up your email campaigns, you need to determine what flow you want the user to experience and flag your email link accordingly.</p><p>Use the following markup for the links to work properly:</p><ul><li><strong>Deep linking users to in-app content</strong>: add <code>$deep_link=true</code> to your links as a query parameter</li><li><strong>Linking users to web-only content</strong>: add <code>$web_only=true</code> to your links as a query parameter</li></ul><p><strong>2. Configure Clevertap</strong></p><p>Please follow all of the <a href="./clevertap-data.html#configure-clevertap">Configure Clevertap</a> steps to ensure everything is working properly before you go live.</p><h2 id="sendgrid" tabindex="-1">Sendgrid <a class="header-anchor" href="#sendgrid" aria-label="Permalink to &quot;Sendgrid&quot;">​</a></h2><p><strong>1. Create Flagged Links</strong></p><p>Before you start setting up your email campaigns, you need to determine what flow you want the user to experience and flag your email link accordingly.</p><p>Use the following markup for the links to work properly:</p><ul><li><strong>Deep linking users to in-app content</strong>: add <code>universal=&quot;true&quot;</code> to the HTML</li><li><strong>Linking users to web-only content</strong>: No need to add anything</li></ul><p><strong>2. Configure Clevertap</strong></p><p>Please follow all of the <a href="./clevertap-data.html#configure-clevertap">Configure Clevertap</a> steps to ensure everything is working properly before you go live.</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>**Analytics on the Branch Dashboard**</span></span>
<span class="line"><span></span></span>
<span class="line"><span>        To see how the email campaigns have performed and break it down into campaigns, it is very essential to tag your email links with the ~campaign tag. If your team uses UTM tags, Branch will also ingest the UTM_campaign tag. This will help dedupe the numbers and hence see the downstream events. You can add the campaign tag in any comparisons and filters in any Dashboard views.</span></span></code></pre></div>`,55)])])}const g=a(r,[["render",n]]);export{c as __pageData,g as default};
